const ethers = require('ethers');

const ERC20_ABI = [
  'function name() view returns (string)',
  'function symbol() view returns (string)',
  'function decimals() view returns (uint8)',
  'function balanceOf(address) view returns (uint256)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function transfer(address to, uint256 amount) returns (bool)',
  'event Approval(address indexed owner, address indexed spender, uint256 value)',
  'event Transfer(address indexed from, address indexed to, uint256 value)'
];

const DEX_ABI = [
  'function getAmountOut(uint256 amountIn, address tokenIn, address tokenOut) view returns (uint256)',
  'function swap(address tokenIn, address tokenOut, uint256 amountIn, uint256 minAmountOut, address to) returns (uint256)',
  'function addLiquidity(address tokenA, address tokenB, uint256 amountA, uint256 amountB) returns (uint256)',
  'function removeLiquidity(address tokenA, address tokenB, uint256 liquidity) returns (uint256, uint256)',
  'event Swap(address indexed user, address indexed tokenIn, address indexed tokenOut, uint256 amountIn, uint256 amountOut)',
  'event LiquidityAdded(address indexed user, address indexed tokenA, address indexed tokenB, uint256 amountA, uint256 amountB)',
  'event LiquidityRemoved(address indexed user, address indexed tokenA, address indexed tokenB, uint256 amountA, uint256 amountB)'
];

class TokenSwapDApp {
  constructor(dexAddress) {
    this.dexAddress = dexAddress;
    this.provider = null;
    this.signer = null;
    this.dexContract = null;
    this.userAddress = null;
    this.MAX_UINT256 = ethers.MaxUint256;
  }

  async connectWallet() {
    if (typeof window.ethereum === 'undefined') {
      throw new Error('MetaMask or Web3 wallet not detected');
    }

    this.provider = new ethers.BrowserProvider(window.ethereum);
    await this.provider.send('eth_requestAccounts', []);
    this.signer = await this.provider.getSigner();
    this.userAddress = await this.signer.getAddress();
    this.dexContract = new ethers.Contract(this.dexAddress, DEX_ABI, this.signer);

    return this.userAddress;
  }

  async disconnectWallet() {
    this.provider = null;
    this.signer = null;
    this.dexContract = null;
    this.userAddress = null;
  }

  getTokenContract(tokenAddress) {
    if (!this.signer) {
      throw new Error('Wallet not connected');
    }
    return new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);
  }

  async getTokenInfo(tokenAddress) {
    const tokenContract = this.getTokenContract(tokenAddress);
    
    const [name, symbol, decimals] = await Promise.all([
      tokenContract.name(),
      tokenContract.symbol(),
      tokenContract.decimals()
    ]);

    return { name, symbol, decimals, address: tokenAddress };
  }

  async getTokenBalance(tokenAddress, userAddress = null) {
    const address = userAddress || this.userAddress;
    if (!address) {
      throw new Error('No address provided');
    }

    const tokenContract = this.getTokenContract(tokenAddress);
    const balance = await tokenContract.balanceOf(address);
    const decimals = await tokenContract.decimals();

    return {
      raw: balance.toString(),
      formatted: ethers.formatUnits(balance, decimals)
    };
  }

  async checkAllowance(tokenAddress, spenderAddress = null) {
    const spender = spenderAddress || this.dexAddress;
    const tokenContract = this.getTokenContract(tokenAddress);
    
    const allowance = await tokenContract.allowance(this.userAddress, spender);
    const decimals = await tokenContract.decimals();

    return {
      raw: allowance.toString(),
      formatted: ethers.formatUnits(allowance, decimals),
      isMaxApproved: allowance >= this.MAX_UINT256 / 2n
    };
  }

  async approveToken(tokenAddress, spenderAddress = null, amount = null) {
    const spender = spenderAddress || this.dexAddress;
    const approvalAmount = amount || this.MAX_UINT256;
    
    const tokenContract = this.getTokenContract(tokenAddress);
    
    const tx = await tokenContract.approve(spender, approvalAmount);
    console.log(`Approval transaction sent: ${tx.hash}`);
    
    const receipt = await tx.wait();
    console.log(`Approval confirmed in block ${receipt.blockNumber}`);
    
    return {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status
    };
  }

  async approveMaxAmount(tokenAddress, spenderAddress = null) {
    return await this.approveToken(tokenAddress, spenderAddress, this.MAX_UINT256);
  }

  async ensureApproval(tokenAddress, requiredAmount, spenderAddress = null) {
    const spender = spenderAddress || this.dexAddress;
    const allowanceInfo = await this.checkAllowance(tokenAddress, spender);
    
    const requiredAmountBN = ethers.parseUnits(requiredAmount.toString(), 18);
    
    if (BigInt(allowanceInfo.raw) < requiredAmountBN) {
      console.log('Insufficient allowance, requesting approval...');
      return await this.approveMaxAmount(tokenAddress, spender);
    }
    
    console.log('Sufficient allowance already exists');
    return null;
  }

  async getQuote(tokenIn, tokenOut, amountIn) {
    if (!this.dexContract) {
      throw new Error('DEX contract not initialized');
    }

    const tokenInContract = this.getTokenContract(tokenIn);
    const tokenOutContract = this.getTokenContract(tokenOut);
    
    const decimalsIn = await tokenInContract.decimals();
    const decimalsOut = await tokenOutContract.decimals();
    
    const amountInWei = ethers.parseUnits(amountIn.toString(), decimalsIn);
    
    const amountOut = await this.dexContract.getAmountOut(amountInWei, tokenIn, tokenOut);
    
    return {
      amountIn: amountIn.toString(),
      amountOut: ethers.formatUnits(amountOut, decimalsOut),
      amountOutRaw: amountOut.toString()
    };
  }

  async executeSwap(tokenIn, tokenOut, amountIn, slippageTolerance = 0.5) {
    if (!this.dexContract) {
      throw new Error('DEX contract not initialized');
    }

    await this.ensureApproval(tokenIn, amountIn);

    const tokenInContract = this.getTokenContract(tokenIn);
    const tokenOutContract = this.getTokenContract(tokenOut);
    
    const decimalsIn = await tokenInContract.decimals();
    const decimalsOut = await tokenOutContract.decimals();
    
    const amountInWei = ethers.parseUnits(amountIn.toString(), decimalsIn);
    
    const quote = await this.getQuote(tokenIn, tokenOut, amountIn);
    const amountOutWei = BigInt(quote.amountOutRaw);
    
    const slippageMultiplier = (100 - slippageTolerance) / 100;
    const minAmountOut = BigInt(Math.floor(Number(amountOutWei) * slippageMultiplier));
    
    console.log(`Executing swap: ${amountIn} tokens for minimum ${ethers.formatUnits(minAmountOut, decimalsOut)} tokens`);
    
    const tx = await this.dexContract.swap(
      tokenIn,
      tokenOut,
      amountInWei,
      minAmountOut,
      this.userAddress
    );
    
    console.log(`Swap transaction sent: ${tx.hash}`);
    
    const receipt = await tx.wait();
    console.log(`Swap confirmed in block ${receipt.blockNumber}`);
    
    const swapEvent = receipt.logs.find(log => {
      try {
        const parsed = this.dexContract.interface.parseLog(log);
        return parsed.name === 'Swap';
      } catch {
        return false;
      }
    });

    let actualAmountOut = '0';
    if (swapEvent) {
      const parsed = this.dexContract.interface.parseLog(swapEvent);
      actualAmountOut = ethers.formatUnits(parsed.args.amountOut, decimalsOut);
    }

    return {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status,
      amountIn: amountIn.toString(),
      amountOut: actualAmountOut,
      gasUsed: receipt.gasUsed.toString()
    };
  }

  async addLiquidity(tokenA, tokenB, amountA, amountB) {
    if (!this.dexContract) {
      throw new Error('DEX contract not initialized');
    }

    await this.ensureApproval(tokenA, amountA);
    await this.ensureApproval(tokenB, amountB);

    const tokenAContract = this.getTokenContract(tokenA);
    const tokenBContract = this.getTokenContract(tokenB);
    
    const decimalsA = await tokenAContract.decimals();
    const decimalsB = await tokenBContract.decimals();
    
    const amountAWei = ethers.parseUnits(amountA.toString(), decimalsA);
    const amountBWei = ethers.parseUnits(amountB.toString(), decimalsB);
    
    const tx = await this.dexContract.addLiquidity(tokenA, tokenB, amountAWei, amountBWei);
    console.log(`Add liquidity transaction sent: ${tx.hash}`);
    
    const receipt = await tx.wait();
    console.log(`Add liquidity confirmed in block ${receipt.blockNumber}`);
    
    return {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status,
      amountA: amountA.toString(),
      amountB: amountB.toString()
    };
  }

  async removeLiquidity(tokenA, tokenB, liquidityAmount) {
    if (!this.dexContract) {
      throw new Error('DEX contract not initialized');
    }

    const liquidityWei = ethers.parseUnits(liquidityAmount.toString(), 18);
    
    const tx = await this.dexContract.removeLiquidity(tokenA, tokenB, liquidityWei);
    console.log(`Remove liquidity transaction sent: ${tx.hash}`);
    
    const receipt = await tx.wait();
    console.log(`Remove liquidity confirmed in block ${receipt.blockNumber}`);
    
    return {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status,
      liquidityAmount: liquidityAmount.toString()
    };
  }

  async getNetworkInfo() {
    if (!this.provider) {
      throw new Error('Provider not initialized');
    }

    const network = await this.provider.getNetwork();
    const blockNumber = await this.provider.getBlockNumber();
    const gasPrice = await this.provider.getFeeData();

    return {
      chainId: network.chainId.toString(),
      name: network.name,
      blockNumber: blockNumber,
      gasPrice: ethers.formatUnits(gasPrice.gasPrice || 0n, 'gwei')
    };
  }

  async estimateSwapGas(tokenIn, tokenOut, amountIn) {
    if (!this.dexContract) {
      throw new Error('DEX contract not initialized');
    }

    const tokenInContract = this.getTokenContract(tokenIn);
    const decimalsIn = await tokenInContract.decimals();
    const amountInWei = ethers.parseUnits(amountIn.toString(), decimalsIn);
    
    const quote = await this.getQuote(tokenIn, tokenOut, amountIn);
    const minAmountOut = BigInt(quote.amountOutRaw) * 95n / 100n;

    const gasEstimate = await this.dexContract.swap.estimateGas(
      tokenIn,
      tokenOut,
      amountInWei,
      minAmountOut,
      this.userAddress
    );

    const feeData = await this.provider.getFeeData();
    const gasCost = gasEstimate * (feeData.gasPrice || 0n);

    return {
      gasLimit: gasEstimate.toString(),
      gasPrice: ethers.formatUnits(feeData.gasPrice || 0n, 'gwei'),
      estimatedCost: ethers.formatEther(gasCost)
    };
  }

  async waitForTransaction(txHash) {
    if (!this.provider) {
      throw new Error('Provider not initialized');
    }

    console.log(`Waiting for transaction: ${txHash}`);
    const receipt = await this.provider.waitForTransaction(txHash);
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status,
      gasUsed: receipt.gasUsed.toString()
    };
  }

  onTransactionUpdate(callback) {
    if (!this.provider) {
      throw new Error('Provider not initialized');
    }

    this.provider.on('block', async (blockNumber) => {
      callback({ type: 'block', blockNumber });
    });
  }

  removeAllListeners() {
    if (this.provider) {
      this.provider.removeAllListeners();
    }
  }
}

